CREATE TABLE IF NOT EXISTS webhooks(id TEXT PRIMARY KEY,url TEXT NOT NULL,secret TEXT NOT NULL DEFAULT '',events TEXT NOT NULL DEFAULT '',active INTEGER NOT NULL DEFAULT 1,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS webhook_deliveries(id TEXT PRIMARY KEY,webhook_id TEXT NOT NULL,event TEXT NOT NULL,status INTEGER NOT NULL DEFAULT 0,attempts INTEGER NOT NULL DEFAULT 0,last_error TEXT NOT NULL DEFAULT '',created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS idx_webhook_deliveries_hook ON webhook_deliveries(webhook_id,created_at DESC);
